package com.projectbible.post.gradle.jpa.postgresql.post.application;
import java.util.List; import java.util.Map; import java.util.stream.Collectors; import org.springframework.stereotype.Service;
@Service public class PostQueryService { private final List<Map<String,Object>> items=List.of(Map.of("id",1,"boardId",1,"title","Welcome to Project Bible","content","Baseline post content","viewCount",42,"likeCount",7,"commentCount",3,"status","ACTIVE"),Map.of("id",2,"boardId",1,"title","Second post","content","Another baseline post","viewCount",15,"likeCount",2,"commentCount",1,"status","ACTIVE")); public List<Map<String,Object>> list(Long boardId) { return items.stream().filter(i->boardId==null||((Number)i.get("boardId")).longValue()==boardId).map(this::summary).collect(Collectors.toList()); } public Map<String,Object> one(long id) { return items.stream().filter(i->((Number)i.get("id")).longValue()==id).findFirst().orElseThrow(()->new IllegalArgumentException("Post not found: "+id)); } private Map<String,Object> summary(Map<String,Object> post) { return Map.of("id",post.get("id"),"boardId",post.get("boardId"),"title",post.get("title"),"viewCount",post.get("viewCount"),"likeCount",post.get("likeCount"),"commentCount",post.get("commentCount"),"status",post.get("status")); } }
